// - When sel is 00, the output is a[3]
// - When sel is 01, the output is a[2]
// - When sel is 10, the output is a[1]
// - When sel is 11, the output is a[0]
module top_module (
    input [3:0] a,
    input [1:0] sel,
    output reg out);always @(*)
    case (sel)
        2'b00: out = a[0];
        2'b01: out = a[1];
        2'b10: out = a[2];
        2'b11: out = a[3];
    endcase

endmodule

